// Validar ventana de llamadas: 08:00 – 19:00 hrs (Proforma V4.1 §6)
const ahora = new Date();
const hora = ahora.getHours();

if (hora < 8 || hora >= 19) {
  return [{ json: {
    ...($input.first().json),
    dentro_ventana: false,
    motivo: `Llamada fuera de ventana permitida (${hora}:${String(ahora.getMinutes()).padStart(2,'0')} hrs). Ventana: 08:00–19:00.`
  }}];
}

return [{ json: { ...($input.first().json), dentro_ventana: true } }];

// Programar reintento fuera de horario — guardar el lead para mañana 08:00
const lead = $input.first().json;
const intentos = lead.intentos_llamada || 0;

if (intentos >= 4) {
  return [{ json: { ...lead, accion: 'DESCARTAR', motivo: 'Fuera de ventana por 4 días consecutivos — descarte por abandono' } }];
}

return [{ json: {
  ...lead,
  accion: 'REINTENTAR',
  intentos_llamada: intentos + 1,
  proxima_llamada: 'Mañana 08:00 hrs'
} }];

const resultado = $input.first().json;
const transcripcion = resultado.transcripts?.join(' ') || resultado.summary || resultado.concatenated_transcript || '';

let decision = 'VOLVER_A_LLAMAR';
if (transcripcion.includes('SI_INTERESADO') ||
    transcripcion.toLowerCase().includes('si me interesa') ||
    transcripcion.toLowerCase().includes('sí quiero')) {
  decision = 'SI_INTERESADO';
} else if (transcripcion.includes('NO_INTERESADO') ||
           transcripcion.toLowerCase().includes('no me interesa') ||
           transcripcion.toLowerCase().includes('no gracias')) {
  decision = 'NO_INTERESADO';
}

return [{ json: {
  call_id: resultado.call_id,
  duracion_segundos: resultado.call_length,
  decision,
  grabacion_url: resultado.recording_url,
  transcripcion: transcripcion,
  telefono: resultado.to,
  timestamp: new Date().toISOString()
} }];

// ================================================================
// SEGUIMIENTO: 4 mensajes automáticos en 3 días (Proforma V4.1 §6)
// ================================================================
const lead = $input.first().json;
const intentos = lead.intentos_seguimiento || 0;

const mensajes = [
  "Buenos días 👋 Le habla el equipo de *Punto Clínico*. Le llamamos respecto al incremento en su pensión IMSS. ¿Sería posible que le devolvamos la llamada en los próximos minutos?",
  "Estimado/a, seguimos tratando de comunicarnos con usted sobre su solicitud de incremento de pensión. Recuerde que este trámite no tiene ningún costo hasta que tenga el dinero en manos. ¿Cuándo le es posible hablar?",
  "Tercer intento de contacto. Su expediente está listo para iniciar. No le pediremos nada adelantado — solo queremos presentarle los detalles. ¿Tiene un momento hoy?",
  "Último intento de contacto. Si no recibimos respuesta, cerraremos su solicitud. Si desea continuar, por favor escríbanos o responda este mensaje. ¡Gracias por su tiempo!"
];

if (intentos >= 4) {
  return [{ json: {
    ...lead,
    accion: 'DESCARTAR',
    motivo: 'Sin respuesta tras 4 intentos de seguimiento en 3 días'
  } }];
}

return [{ json: {
  ...lead,
  accion: 'ENVIAR_SEGUIMIENTO',
  mensaje_seguimiento: mensajes[intentos],
  intento_num: intentos + 1,
  intentos_seguimiento: intentos + 1
} }];

// ================================================================
// ASIGNACIÓN ROUND-ROBIN — 6 agentes humanos (Proforma V4.1 §6)
// El agente asignado es propietario permanente del lead.
// Entre agentes NO hay visibilidad cruzada de leads.
// ================================================================
const AGENTES = [
  { id: 'AGT-01', nombre: 'Agente 1', telefono: process.env.AGENTE_1_TEL || '' },
  { id: 'AGT-02', nombre: 'Agente 2', telefono: process.env.AGENTE_2_TEL || '' },
  { id: 'AGT-03', nombre: 'Agente 3', telefono: process.env.AGENTE_3_TEL || '' },
  { id: 'AGT-04', nombre: 'Agente 4', telefono: process.env.AGENTE_4_TEL || '' },
  { id: 'AGT-05', nombre: 'Agente 5', telefono: process.env.AGENTE_5_TEL || '' },
  { id: 'AGT-06', nombre: 'Agente 6', telefono: process.env.AGENTE_6_TEL || '' }
];

// Contador global de asignaciones usando timestamp para distribuir
const contadorBase = Math.floor(Date.now() / 1000);
const indice = contadorBase % AGENTES.length;
const agenteAsignado = AGENTES[indice];

return [{ json: {
  ...($input.first().json),
  asesor_propietario: agenteAsignado.id,
  asesor_nombre: agenteAsignado.nombre,
  asesor_telefono: agenteAsignado.telefono,
  timestamp_asignacion: new Date().toISOString()
} }];

